        "id": "01f0eab8c15d11eca1b28bd944433fab",
        "question": [
          "What is the total paid gross due for pharmacy claims by pay type?"
        ],
        "sql": [
          "SELECT\n",
          "  `pay_type`,\n",
          "  SUM(`paid_gross_due`) AS total_paid_gross_due\n",
          "FROM\n",
          "  `healthverity_claims_sample_patient_dataset`.`hv_claims_sample`.`pharmacy_claim`\n",
          "WHERE\n",
          "  `pay_type` IS NOT NULL\n",
          "  AND `paid_gross_due` IS NOT NULL\n",
          "GROUP BY\n",
          "  `pay_type`\n",
          "ORDER BY\n",
          "  total_paid_gross_due DESC"
        ]
      },
