        ],
        "sql": [
          "SELECT\n",
          "  MIN(`days_supply`) AS min_days_supply,\n",
          "  MAX(`days_supply`) AS max_days_supply,\n",
          "  AVG(`days_supply`) AS avg_days_supply\n",
          "FROM\n",
          "  `healthverity_claims_sample_patient_dataset`.`hv_claims_sample`.`pharmacy_claim`\n",
          "WHERE\n",
          "  `days_supply` IS NOT NULL"
        ]
      },
      {
        "id": "01f0eabd844e1b55bb1c2286df9ff098",
        "question": [
          "What is the distribution of pay types in the medical_claim table?"
        ],
        "sql": [
          "SELECT\n",
          "  `pay_type`,\n",
          "  COUNT(*) AS claim_count\n",
          "FROM\n",
          "  `healthverity_claims_sample_patient_dataset`.`hv_claims_sample`.`medical_claim`\n",
          "WHERE\n",
          "  `pay_type` IS NOT NULL\n",
          "GROUP BY\n",
          "  `pay_type`\n",
          "ORDER BY\n",
          "  claim_count DESC"
        ]
      }
